class Solution:
    def maxRectangleArea(self, points):
        # independent re-derivation: check every combination of four points
        # directly rather than crossing distinct x/y coordinate pairs
        from itertools import combinations
        pts = [tuple(p) for p in points]
        pt_set = set(pts)
        best = -1
        for a, b, c, d in combinations(pts, 4):
            xs = {a[0], b[0], c[0], d[0]}
            ys = {a[1], b[1], c[1], d[1]}
            if len(xs) != 2 or len(ys) != 2:
                continue
            x1, x2 = sorted(xs)
            y1, y2 = sorted(ys)
            corners = {(x1, y1), (x1, y2), (x2, y1), (x2, y2)}
            if corners != {a, b, c, d}:
                continue
            ok = True
            for p in pt_set:
                if x1 <= p[0] <= x2 and y1 <= p[1] <= y2 and p not in corners:
                    ok = False
                    break
            if ok:
                area = (x2 - x1) * (y2 - y1)
                if area > best:
                    best = area
        return best

