class Solution:
    def maxRectangleArea(self, points):
        pts = set(tuple(p) for p in points)
        xs = sorted(set(p[0] for p in points))
        ys = sorted(set(p[1] for p in points))
        best = -1
        for ai in range(len(xs)):
            for bi in range(ai + 1, len(xs)):
                x1, x2 = xs[ai], xs[bi]
                for ci in range(len(ys)):
                    for di in range(ci + 1, len(ys)):
                        y1, y2 = ys[ci], ys[di]
                        corners = [(x1, y1), (x1, y2), (x2, y1), (x2, y2)]
                        if not all(c in pts for c in corners):
                            continue
                        ok = True
                        for p in pts:
                            if x1 <= p[0] <= x2 and y1 <= p[1] <= y2 and p not in corners:
                                ok = False
                                break
                        if ok:
                            area = (x2 - x1) * (y2 - y1)
                            if area > best:
                                best = area
        return best

