var maxRectangleArea = function(points) {
    const ptSet = new Set(points.map(p => p[0] + ',' + p[1]));
    const xs = Array.from(new Set(points.map(p => p[0]))).sort((a, b) => a - b);
    const ys = Array.from(new Set(points.map(p => p[1]))).sort((a, b) => a - b);
    let best = -1;
    for (let a = 0; a < xs.length; a++) {
        for (let b = a + 1; b < xs.length; b++) {
            const x1 = xs[a], x2 = xs[b];
            for (let c = 0; c < ys.length; c++) {
                for (let d = c + 1; d < ys.length; d++) {
                    const y1 = ys[c], y2 = ys[d];
                    if (ptSet.has(x1 + ',' + y1) && ptSet.has(x1 + ',' + y2) &&
                        ptSet.has(x2 + ',' + y1) && ptSet.has(x2 + ',' + y2)) {
                        let ok = true;
                        for (const [px, py] of points) {
                            if (px >= x1 && px <= x2 && py >= y1 && py <= y2) {
                                const isCorner = (px === x1 || px === x2) && (py === y1 || py === y2);
                                if (!isCorner) { ok = false; break; }
                            }
                        }
                        if (ok) {
                            const area = (x2 - x1) * (y2 - y1);
                            if (area > best) best = area;
                        }
                    }
                }
            }
        }
    }
    return best;
};
